<span class="line"><span style="color:#F8F8F2;">Enter an integer </span><span style="color:#F92672;">or</span><span style="color:#F8F8F2;"> the string </span><span style="color:#E6DB74;">&quot;end&quot;</span><span style="color:#F8F8F2;">: </span><span style="color:#AE81FF;">4</span></span>
